185→function getTotalDuration(epId) {
186→  const chunks = chunkData[epId] || [];
187→  return chunks.reduce((s, c) => s + (c.duration || 0), 0);
188→}
189→
190→function getChunkAtTime(epId, t) {
191→  const chunks = chunkData[epId] || [];
192→  let acc = 0;
193→  for (const c of chunks) {
194→    if (t >= acc && t < acc + c.duration) {
195→      return { chunk: c, startInGlobal: acc };
196→    }
197→    acc += c.duration;
198→  }
199→  return chunks.length > 0 ? { chunk: chunks[chunks.length - 1], startInGlobal: acc - chunks[chunks.length - 1].duration } : null;
200→}
