212→function getDirtyType(chunkId) {
213→  const e = state.edits[chunkId];
214→  if (!e) return null;
215→  if (e.tts !== undefined && e.subtitle !== undefined) return 'both';
216→  if (e.tts !== undefined) return 'tts';
217→  if (e.subtitle !== undefined) return 'subtitle';
218→  return null;
219→}
