221→function countDirty() {
222→  let tts = 0, sub = 0;
223→  for (const e of Object.values(state.edits)) {
224→    if (e.tts !== undefined) tts++;
225→    if (e.subtitle !== undefined) sub++;
226→  }
227→  return { tts, sub };
228→}
