461→function renderKaraoke(text, pct) {
462→  const chars = Array.from(text);
463→  const cut = Math.floor(chars.length * pct / 100);
464→  const played = escapeHtml(chars.slice(0, cut).join(''));
465→  const rest   = escapeHtml(chars.slice(cut).join(''));
466→  return `<span class="text-neutral-900 font-medium">${played}</span><span class="text-neutral-300">${rest}</span>`;
467→}
