577→// ============================================================
578→// CHUNK PLAYER (单 chunk 播放)
579→// ============================================================
580→function togglePlayChunk(chunkId) {
581→  // 切换:同 id 再点 = 暂停
582→  if (state.playingChunkId === chunkId) {
583→    stopChunkPlay();
584→    renderMain();
585→    return;
586→  }
587→  // 切到新 chunk
588→  stopChunkPlay();
589→  const chunk = (chunkData[state.selectedId] || []).find(c => c.id === chunkId);
590→  if (!chunk || chunk.status !== 'done') return;
591→
592→  state.playingChunkId = chunkId;
593→  state.chunkPlayElapsed = 0;
594→  // mock: 按 chunk.duration 计时,到时自动停
595→  state.chunkPlayTimer = setInterval(() => {
596→    state.chunkPlayElapsed += 0.1;
597→    if (state.chunkPlayElapsed >= chunk.duration) {
598→      stopChunkPlay();
599→      renderMain();
600→    } else {
601→      // 局部更新进度,不全 re-render(避免编辑面板闪)
602→      updatePlayingRow();
603→    }
604→  }, 100);
605→  renderMain();
606→}
