608→function updatePlayingRow() {
609→  const id = state.playingChunkId;
610→  if (!id) return;
611→  const row = document.getElementById(`row-${id}`);
612→  if (!row) return;
613→  const chunk = (chunkData[state.selectedId] || []).find(c => c.id === id);
614→  if (!chunk) return;
615→  const pct = Math.min(100, (state.chunkPlayElapsed / chunk.duration) * 100);
616→
617→  // 重新生成卡拉 OK 字符遮罩
618→  const e = state.edits[id] || {};
619→  const text = e.subtitle !== undefined
620→    ? stripControlMarkers(e.subtitle)
621→    : getDisplaySubtitle(chunk);
622→  const subCell = row.querySelector('td:nth-child(5) > div:first-child');
623→  if (subCell) subCell.innerHTML = renderKaraoke(text, pct);
624→
625→  // 更新时间显示
626→  const txt = row.querySelector('td:nth-child(5) .mono');
627→  if (txt) txt.textContent = `${state.chunkPlayElapsed.toFixed(1)}s / ${chunk.duration}s`;
628→}
629→
630→function stopChunkPlay() {
631→  if (state.chunkPlayTimer) clearInterval(state.chunkPlayTimer);
632→  state.chunkPlayTimer = null;
633→  state.playingChunkId = null;
634→  state.chunkPlayElapsed = 0;
635→}
