637→// ============================================================
638→// EDIT
639→// ============================================================
640→function startEdit(chunkId) {
641→  // 编辑期间允许继续播放,只在 Stage 后才禁用
642→  state.editing = chunkId;
643→  renderMain();
644→  setTimeout(() => {
645→    const ta = document.getElementById('edit-tts');
