662→function stageEdit(chunkId) {
663→  const ttsEl = document.getElementById('edit-tts');
664→  const subEl = document.getElementById('edit-sub');
665→  const chunk = chunkData[state.selectedId].find(c => c.id === chunkId);
666→  if (!chunk) return;
667→
668→  const newTts = ttsEl.value;
669→  const newSub = subEl.value;
670→  const origSub = chunk.subtitle_text || '';
671→
672→  if (!state.edits[chunkId]) state.edits[chunkId] = {};
673→
674→  // 只把"实际发生改动"的字段记入 edits
675→  if (newTts !== chunk.text_normalized) {
676→    state.edits[chunkId].tts = newTts;
677→  } else {
678→    delete state.edits[chunkId].tts;
679→  }
680→
681→  if (newSub !== origSub) {
682→    state.edits[chunkId].subtitle = newSub;
683→  } else {
684→    delete state.edits[chunkId].subtitle;
685→  }
686→
687→  if (Object.keys(state.edits[chunkId]).length === 0) {
688→    delete state.edits[chunkId];
689→    toast('没有改动');
690→  } else {
691→    const types = [];
692→    if (state.edits[chunkId].tts !== undefined) types.push('TTS');
693→    if (state.edits[chunkId].subtitle !== undefined) types.push('字幕');
694→    toast(`已暂存 ${chunkId} (${types.join('+')}),播放已禁用,Apply 后恢复`);
695→    // 暂存后该 chunk 进入 dirty 状态,如果正在播这个 chunk 就停掉
696→    if (state.playingChunkId === chunkId) stopChunkPlay();
697→  }
698→
699→  state.editing = null;
700→  renderMain();
701→}
702→
703→function discardEdits() {
704→  state.edits = {};
705→  renderMain();
706→  toast('已丢弃所有暂存改动');
707→}
708→
709→function applyEdits() {
710→  const { tts, sub } = countDirty();
711→  const total = tts + sub;
712→  if (total === 0) return;
713→
714→  const msg = [];
715→  if (tts > 0) msg.push(`${tts} 个 TTS 重做`);
716→  if (sub > 0) msg.push(`${sub} 个字幕重生`);
717→  toast(`正在执行: ${msg.join(', ')}`);
718→
719→  // 应用改动到数据
720→  const chunks = chunkData[state.selectedId];
721→  for (const [cid, e] of Object.entries(state.edits)) {
722→    const c = chunks.find(c => c.id === cid);
723→    if (!c) continue;
724→    if (e.tts !== undefined) {
725→      c.text_normalized = e.tts;
726→      c.status = 'pending';
727→      c.duration = 0;
728→    }
729→    if (e.subtitle !== undefined) {
730→      c.subtitle_text = e.subtitle;
731→    }
732→  }
733→  state.edits = {};
734→
735→  episodes[state.selectedId].status = 'running';
736→  episodes[state.selectedId].stage = tts > 0 ? 'P2 → P3 → P5/P6' : 'P5/P6';
737→  renderAll();
738→
739→  // 模拟完成
740→  setTimeout(() => {
741→    for (const c of chunks) {
742→      if (c.status === 'pending') {
743→        c.status = 'done';
744→        c.duration = +(Math.random() * 3 + 3).toFixed(1);
745→      }
746→    }
747→    episodes[state.selectedId].status = 'done';
748→    episodes[state.selectedId].stage = '';
749→    renderAll();
750→    toast('Redo 完成');
751→  }, 2500);
752→}
753→
754→// ============================================================
755→// EPISODE / RUN
756→// ============================================================
757→function selectEp(id) {
758→  state.selectedId = id;
759→  state.editing = null;
760→  stopChunkPlay();
761→  renderAll();
