772→  setTimeout(() => { ep.stage = 'P2 (3/8)'; renderSidebar(); renderMain(); }, 800);
773→  setTimeout(() => { ep.stage = 'P3 (5/8)'; renderSidebar(); renderMain(); }, 1800);
774→  setTimeout(() => {
775→    ep.status = 'done'; ep.stage = '';
776→    for (const c of chunkData[ep.id] || []) { if (c.status !== 'done') { c.status = 'done'; c.duration = 4.5; } }
777→    renderAll();
778→    toast('Pipeline 完成');
779→  }, 3000);
780→}
