export async function runEpisode(id: string) {
  if (USE_FIXTURES) {
    await new Promise((r) => setTimeout(r, 1500));
    return { jobId: "fake", startedAt: new Date().toISOString() };
  }
  const r = await fetch(`/api/episodes/${id}/run`, { method: "POST" });
  if (r.status === 409) throw new Error("busy");
  if (!r.ok) throw new Error(`${r.status}`);
  return r.json();
}

export async function applyEdits(
  id: string,
  edits: Record<string, ChunkEdit>,
) {
  if (USE_FIXTURES) {
    await new Promise((r) => setTimeout(r, 1500));
    return { jobId: "fake", startedAt: new Date().toISOString() };
  }
  const r = await fetch(`/api/episodes/${id}/apply`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ edits }),
  });
  if (r.status === 409) throw new Error("busy");
  if (!r.ok) throw new Error(`${r.status}`);
  return r.json();
}

export async function retryChunk(id: string, cid: string, count: number) {
  if (USE_FIXTURES) {
    await new Promise((r) => setTimeout(r, count * 800));
    return { jobId: "fake", startedAt: new Date().toISOString() };
  }
  const r = await fetch(
    `/api/episodes/${id}/chunks/${cid}/retry?count=${count}`,
    { method: "POST" },
  );
  if (r.status === 409) throw new Error("busy");
  if (!r.ok) throw new Error(`${r.status}`);
  return r.json();
}

export async function exportEpisode(id: string, targetDir: string) {
  if (USE_FIXTURES) {
    await new Promise((r) => setTimeout(r, 500));
    return { filesCopied: 8, totalBytes: 0 };
  }
  const r = await fetch(`/api/episodes/${id}/export`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ targetDir }),
  });
  if (!r.ok) throw new Error(`${r.status}`);
  return r.json();
}

export async function createEpisode(id: string, file: File) {
  if (USE_FIXTURES) {
    await new Promise((r) => setTimeout(r, 500));
    return { id, status: "ready" };
  }
  const fd = new FormData();
  fd.append("id", id);
  fd.append("script", file);
  const r = await fetch("/api/episodes", { method: "POST", body: fd });
  if (!r.ok) throw new Error(`${r.status}`);
  return r.json();
}

// audio URL helper
export function getAudioUrl(
  epId: string,
  cid: string,
  takeId: string,
): string {
  if (USE_FIXTURES) return "";
  return `/api/audio/${epId}/${cid}/${takeId}`;
}

/**
 * Frontend 共享小工具函数。
 * 这里不 import 任何 adapter / server-only 代码。
 */

/** Strip S2-Pro 控制标记,供字幕显示用。与 P5 脚本的行为一致。 */
export function stripControlMarkers(text: string | null | undefined): string {
  return String(text ?? "")
    .replace(/\[(?:break|breath|long[ -]break)\]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

/** 得到字幕显示文本:优先 subtitleText,否则 strip 后的 text。 */
export function getDisplaySubtitle(c: {
  text: string;
  subtitleText: string | null;
}): string {
  if (c.subtitleText != null) return stripControlMarkers(c.subtitleText);
  return stripControlMarkers(c.text);
}

export function fmtDuration(s: number): string {
  if (!s || s <= 0) return "—";
  return `${s.toFixed(1)}s`;
}

