"use client";

import type { Chunk, ChunkEdit, ChunkStatus } from "@/lib/types";
import { getDisplaySubtitle, stripControlMarkers } from "@/lib/utils";
import { KaraokeSubtitle } from "./KaraokeSubtitle";
import { TakeSelector } from "./TakeSelector";

export type DirtyType = null | "tts" | "subtitle" | "both";

interface Props {
  chunk: Chunk;
  isPlaying: boolean;
  isEditing: boolean;
  dirty: DirtyType;
  edit?: ChunkEdit;
  onPlay: () => void;
  onEdit: () => void;
  onCancelEdit: () => void;
}

function statusIcon(status: ChunkStatus) {
  switch (status) {
    case "transcribed":
    case "synth_done":
      return <span className="text-emerald-500">✓</span>;
    case "pending":
      return <span className="text-neutral-300">○</span>;
    case "failed":
      return <span className="text-red-500">✗</span>;
    default:
      return <span className="text-neutral-300">○</span>;
  }
}

export function ChunkRow({
  chunk,
  isPlaying,
  isEditing,
  dirty,
  edit,
  onPlay,
  onEdit,
  onCancelEdit,
}: Props) {
  const isDirty = dirty !== null;
  const hasSubField = chunk.subtitleText != null;

  // 当前生效的 display 文本:优先暂存中的 subtitle 编辑
  const displaySubtitle =
    edit?.subtitleText !== undefined
      ? stripControlMarkers(edit.subtitleText)
      : getDisplaySubtitle(chunk);

  const currentTake = chunk.takes.find((t) => t.id === chunk.selectedTakeId);
  const durationS = currentTake?.durationS ?? 0;

  // Stage change 后禁用播放(必须 Apply/Discard 才能再听)
  const canPlay =
    (chunk.status === "synth_done" || chunk.status === "transcribed") &&
    !isDirty;

  const rowBg = isPlaying
    ? "bg-blue-50 shadow-[inset_3px_0_0_#2563eb]"
    : isEditing
      ? "bg-neutral-50"
      : isDirty
        ? "bg-amber-50/30 hover:bg-amber-50/50"
        : "hover:bg-neutral-50";

  let dirtyBadge: string | null = null;
  if (dirty === "tts") dirtyBadge = "TTS dirty";
  else if (dirty === "subtitle") dirtyBadge = "SUB dirty";
  else if (dirty === "both") dirtyBadge = "TTS+SUB dirty";

  const baseColor = isDirty ? "text-amber-900" : "text-neutral-700";

  return (
    <tr className={`border-b border-neutral-100 ${rowBg}`}>
      <td className="px-6 py-2.5 font-mono text-[11px] text-neutral-500 align-top">
        {chunk.id}
        {hasSubField ? (
          <span
            className="ml-1 text-[9px] text-purple-500"
            title="独立 subtitleText"
          >
            ◆
          </span>
        ) : null}
      </td>
      <td className="py-2.5 align-top">{statusIcon(chunk.status)}</td>
      <td className="py-2.5 align-top text-[11px] text-neutral-500 font-mono">
        {durationS > 0 ? `${durationS.toFixed(1)}s` : "—"}
      </td>
      <td className="py-2.5 align-top">
        <button
          type="button"
          onClick={onPlay}
          disabled={!canPlay}
          title={isDirty ? "有暂存改动,Apply 后才能播放" : ""}
          className={`w-7 h-7 inline-flex items-center justify-center rounded ${
            canPlay
              ? "hover:bg-neutral-200 text-neutral-700"
              : "text-neutral-300 cursor-not-allowed"
          } ${isPlaying ? "bg-neutral-900 text-white hover:bg-neutral-800" : ""}`}
        >
          {isPlaying ? "⏸" : "▶"}
        </button>
      </td>
      <td className="py-2.5 pr-6 align-top">
        <div className="flex items-start flex-wrap">
          <div className="flex-1 min-w-0">
            <KaraokeSubtitle
              text={displaySubtitle}
              durationS={durationS}
              isPlaying={isPlaying}
              baseColorClass={baseColor}
            />
          </div>
          {dirtyBadge ? (
            <span className="ml-2 text-[10px] px-1.5 py-0.5 bg-amber-100 text-amber-700 rounded shrink-0">
              {dirtyBadge}
            </span>
          ) : null}
        </div>
        {chunk.takes.length > 1 ? (
          <TakeSelector
            takes={chunk.takes}
            selectedTakeId={chunk.selectedTakeId}
          />
        ) : null}
      </td>
      <td className="py-2.5 pr-6 align-top text-right">
        <button
          type="button"
          onClick={isEditing ? onCancelEdit : onEdit}
          title={isEditing ? "关闭编辑" : "编辑"}
          className={`w-7 h-7 inline-flex items-center justify-center rounded ${
            isEditing
              ? "bg-neutral-900 text-white hover:bg-neutral-800"
              : "hover:bg-neutral-200 text-neutral-700"
          }`}
        >
          {isEditing ? "✕" : "✎"}
        </button>
      </td>
    </tr>
  );
}

"use client";

import type { Chunk, ChunkEdit, EditBatch } from "@/lib/types";
import { ChunkRow, type DirtyType } from "./ChunkRow";
import { ChunkEditor } from "./ChunkEditor";

interface Props {
  chunks: Chunk[];
  edits: EditBatch;
  editing: string | null;
  playingChunkId: string | null;
  onPlay: (cid: string) => void;
  onEdit: (cid: string) => void;
  onCancelEdit: () => void;
  onStage: (cid: string, draft: ChunkEdit) => void;
}

function computeDirty(edit: ChunkEdit | undefined): DirtyType {
  if (!edit) return null;
  const hasTts = edit.textNormalized !== undefined;
  const hasSub = edit.subtitleText !== undefined;
  if (hasTts && hasSub) return "both";
  if (hasTts) return "tts";
  if (hasSub) return "subtitle";
  return null;
}

export function ChunksTable({
  chunks,
  edits,
  editing,
  playingChunkId,
  onPlay,
  onEdit,
  onCancelEdit,
  onStage,
}: Props) {
  if (chunks.length === 0) {
    return (
      <div className="px-6 py-12 text-center text-sm text-neutral-400">
        还没有 chunks。点 Run 开始第一次合成。
      </div>
    );
  }

  return (
    <table className="w-full text-sm">
      <thead className="text-[11px] text-neutral-400 uppercase tracking-wide">
        <tr className="border-b border-neutral-100">
          <th className="text-left font-medium px-6 py-2 w-44">ID</th>
          <th className="text-left font-medium py-2 w-12">St</th>
          <th className="text-left font-medium py-2 w-16">Dur</th>
          <th className="text-left font-medium py-2 w-12">Play</th>
          <th className="text-left font-medium py-2 pr-6">Subtitle</th>
          <th className="text-right font-medium py-2 pr-6 w-12">Edit</th>
        </tr>
      </thead>
      <tbody>
        {chunks.map((c) => {
          const isEditing = editing === c.id;
          const edit = edits[c.id];
          const dirty = computeDirty(edit);
          return (
            <RowGroup
              key={c.id}
              chunk={c}
              isEditing={isEditing}
              isPlaying={playingChunkId === c.id}
              dirty={dirty}
              edit={edit}
              onPlay={() => onPlay(c.id)}
              onEdit={() => onEdit(c.id)}
              onCancelEdit={onCancelEdit}
              onStage={(draft) => onStage(c.id, draft)}
            />
          );
        })}
      </tbody>
    </table>
  );
}

interface RowGroupProps {
  chunk: Chunk;
  isEditing: boolean;
  isPlaying: boolean;
  dirty: DirtyType;
  edit: ChunkEdit | undefined;
  onPlay: () => void;
  onEdit: () => void;
  onCancelEdit: () => void;
  onStage: (draft: ChunkEdit) => void;
}

function RowGroup({
  chunk,
  isEditing,
  isPlaying,
  dirty,
  edit,
  onPlay,
  onEdit,
  onCancelEdit,
  onStage,
}: RowGroupProps) {
  return (
    <>
      <ChunkRow
        chunk={chunk}
        isPlaying={isPlaying}
        isEditing={isEditing}
        dirty={dirty}
        edit={edit}
        onPlay={onPlay}
        onEdit={onEdit}
        onCancelEdit={onCancelEdit}
      />
      {isEditing ? (
        <ChunkEditor
          chunk={chunk}
          initialDraft={edit}
          onStage={onStage}
          onCancel={onCancelEdit}
        />
      ) : null}
    </>
  );
}

"use client";

import { useEffect, useRef } from "react";

interface Props {
