        <span className="uppercase tracking-wide">run.log</span>
        <span className="ml-auto font-mono">tail -f</span>
      </div>
      <div
        ref={ref}
        className="flex-1 overflow-y-auto px-4 py-2 font-mono text-[11px] leading-relaxed"
      >
        {log.map((line, i) => (
          <div key={i}>{line}</div>
        ))}
